INSERT INTO `additionalservices` VALUES (1,'City Tour',21.00,'/Hotel/Service/city_tour.jpg','Khám phá các địa điểm nổi tiếng và văn hóa đặc sắc của thành phố với hướng dẫn viên chuyên nghiệp.','2025-04-16 20:42:10','2025-12-08 16:03:24'),(2,'Airport Pickup',25.00,'/Hotel/Service/airport_pickup.jpg','Dịch vụ đón tại sân bay nhanh chóng, tiện lợi, giúp bạn di chuyển về khách sạn dễ dàng.','2025-04-16 20:42:10','2025-12-08 16:03:24'),(3,'Driver',20.00,'/Hotel/Service/driver.jpg','Thuê tài xế riêng giàu kinh nghiệm, thông thạo đường xá, phục vụ suốt hành trình của bạn.','2025-04-16 20:42:10','2025-12-08 16:03:24'),(4,'Car',30.00,'/Hotel/Service/car.jpg','Nâng cấp lên xe ô tô đời mới, rộng rãi và tiện nghi hơn cho chuyến đi thoải mái.','2025-04-16 20:42:10','2025-12-08 16:03:24'),(5,'Hotel Pickup',25.00,'/Hotel/Service/hotel_pickup.jpg','Xe đón tận nơi tại sảnh khách sạn đúng giờ, không lo trễ chuyến.','2025-04-16 20:42:10','2025-12-08 16:03:24'),(6,'Lunch',10.00,'/Hotel/Service/lunch.jpg','Thưởng thức bữa trưa ngon miệng với thực đơn đa dạng các món ăn địa phương.','2025-11-17 16:54:52','2025-12-08 16:03:24'),(7,'Dinner',10.00,'/Hotel/Service/dinner.jpg','Bữa tối lãng mạn hoặc ấm cúng dành cho gia đình với các món ăn được chế biến cầu kỳ.','2025-11-17 16:55:04','2025-12-08 16:03:24'),(8,'Breakfast',10.00,'/Hotel/Service/breakfast.jpg','Bắt đầu ngày mới đầy năng lượng với suất ăn sáng dinh dưỡng và cà phê.','2025-12-08 15:02:32','2025-12-08 16:03:24'),(10,'âm',0.00,NULL,'hfdsjhjsgfshsjfhhqiourw','2026-01-20 02:29:56','2026-01-20 02:29:56'),(11,'âm',330.00,NULL,'hgsw','2026-01-20 02:35:06','2026-01-20 02:35:06');
