/*!40000 ALTER TABLE `help` DISABLE KEYS */;
INSERT INTO `help` VALUES (1,'Đặt phòng','Làm thế nào để thay đổi ngày đặt phòng?','Để thay đổi ngày, vui lòng liên hệ hotline 1900 xxxx hoặc gửi email hỗ trợ ít nhất 24h trước giờ check-in. Phí chênh lệch có thể được áp dụng.','2025-12-13 10:06:50'),(2,'Đặt phòng','Tôi có thể đặt nhiều phòng cùng lúc không?','Có. Bạn có thể thêm nhiều phòng vào giỏ hàng hoặc thực hiện đặt nhiều lần. Với đoàn trên 10 phòng, vui lòng liên hệ để có giá ưu đãi.','2025-12-13 10:06:50'),(3,'Đặt phòng','Giá phòng trên web tính theo người hay theo phòng?','Giá hiển thị là giá trọn gói cho phòng đó, dựa trên số lượng người tiêu chuẩn (thường là 2 người lớn).','2025-12-13 10:06:50'),(4,'Đặt phòng','Tôi muốn yêu cầu phòng tầng cao/có view đẹp?','Bạn hãy ghi chú vào mục \"Yêu cầu đặc biệt\" khi đặt phòng. Chúng tôi sẽ cố gắng sắp xếp tùy thuộc vào tình trạng phòng trống.','2025-12-13 10:06:50'),(5,'Đặt phòng','Trẻ em đi kèm tính phí như thế nào?','Trẻ em dưới 6 tuổi miễn phí (ngủ chung giường). Trẻ từ 6-12 tuổi phụ thu ăn sáng. Trên 12 tuổi tính như người lớn.','2025-12-13 10:06:50'),(6,'Đặt phòng','Khách sạn có yêu cầu đặt cọc không?','Với các đơn đặt phòng qua website, bạn cần thanh toán trước 100%. Không yêu cầu đặt cọc thêm khi nhận phòng trừ khi có sử dụng dịch vụ phát sinh.','2025-12-13 10:06:50'),(7,'Thanh toán','Tôi muốn xuất hóa đơn đỏ (VAT) cho công ty?','Được. Tại bước thanh toán, vui lòng tích vào ô \"Yêu cầu xuất hóa đơn\" và điền đầy đủ thông tin Mã số thuế, Tên công ty, Địa chỉ.','2025-12-13 10:06:50'),(8,'Thanh toán','Thanh toán bị lỗi nhưng tiền đã trừ thì sao?','Đừng lo lắng. Hãy chụp ảnh màn hình giao dịch và gửi cho chúng tôi qua Zalo hoặc Hotline. Hệ thống sẽ kiểm tra và xác nhận thủ công cho bạn.','2025-12-13 10:06:50'),(9,'Thanh toán','Website có lưu thông tin thẻ tín dụng của tôi không?','Không. Mọi giao dịch thẻ được xử lý qua cổng thanh toán bảo mật của đối tác (VNPAY/Visa). Chúng tôi không lưu mã bảo mật (CVV) của bạn.','2025-12-13 10:06:50'),(10,'Thanh toán','Tôi có thể trả góp không?','Hiện tại chúng tôi chưa hỗ trợ hình thức trả góp cho đặt phòng khách sạn.','2025-12-13 10:06:50'),(11,'Quy định','Giờ nhận phòng và trả phòng quy định là mấy giờ?','Giờ nhận phòng (Check-in): 14:00. Giờ trả phòng (Check-out): 12:00 trưa.','2025-12-13 10:06:50'),(12,'Quy định','Tôi đến sớm có được nhận phòng ngay không?','Việc nhận phòng sớm tùy thuộc vào tình trạng phòng trống. Nhận trước 9:00 sáng có thể tính phí 50-100% giá phòng.','2025-12-13 10:06:50'),(13,'Quy định','Trả phòng muộn (Late check-out) tính phí thế nào?','Trả sau 12:00 đến 15:00 phụ thu 30%. Sau 15:00 đến 18:00 phụ thu 50%. Sau 18:00 tính 100% giá phòng.','2025-12-13 10:06:50'),(14,'Quy định','Khách sạn có cho phép mang thú cưng không?','Rất tiếc, đa số khách sạn của chúng tôi không cho phép mang thú cưng để đảm bảo vệ sinh chung. Vui lòng xem kỹ mục \"Tiện ích\" của từng khách sạn.','2025-12-13 10:06:50'),(15,'Quy định','Khi nhận phòng tôi cần mang giấy tờ gì?','Bạn cần mang theo CCCD/CMND hoặc Hộ chiếu (Passport) bản gốc của tất cả khách lưu trú để làm thủ tục khai báo.','2025-12-13 10:06:50'),(16,'Dịch vụ','Giá phòng đã bao gồm bữa sáng chưa?','Đa số các phòng hạng Deluxe trở lên đã bao gồm bữa sáng Buffet. Hãy kiểm tra kỹ thông tin \"Bao gồm bữa sáng\" trong chi tiết phòng.','2025-12-13 10:06:50'),(17,'Dịch vụ','Khách sạn có xe đưa đón sân bay không?','Có. Chúng tôi cung cấp dịch vụ đưa đón có tính phí. Vui lòng đặt trước ít nhất 24h qua hotline.','2025-12-13 10:06:50'),(18,'Dịch vụ','Có chỗ đậu xe hơi miễn phí không?','Có. Các khách sạn đều có hầm để xe hoặc bãi xe rộng rãi miễn phí cho khách lưu trú.','2025-12-13 10:06:50'),(19,'Dịch vụ','Tôi có thể mượn bàn ủi/máy sấy tóc không?','Trong phòng thường đã trang bị sẵn. Nếu không thấy, bạn có thể liên hệ lễ tân để mượn miễn phí.','2025-12-13 10:06:50'),(20,'Dịch vụ','Wifi ở đây có mạnh không?','Chúng tôi trang bị Wifi tốc độ cao miễn phí phủ sóng toàn bộ khuôn viên khách sạn và trong phòng.','2025-12-13 10:06:50'),(21,'Tài khoản','Làm sao để xóa tài khoản?','Để xóa tài khoản và toàn bộ dữ liệu cá nhân, vui lòng gửi yêu cầu từ email đăng ký đến support@hotelbooking.com.','2025-12-13 10:06:50'),(22,'Tài khoản','Tôi không nhận được email xác nhận?','Vui lòng kiểm tra hộp thư Spam/Rác. Nếu vẫn không thấy, hãy đăng nhập vào mục \"Lịch sử đặt phòng\" để kiểm tra trạng thái đơn.','2025-12-13 10:06:50'),(23,'Khuyến mãi','Làm sao để sử dụng mã giảm giá?','Tại bước thanh toán, bạn nhập mã vào ô \"Voucher/Mã giảm giá\" và bấm Áp dụng. Hệ thống sẽ tự trừ tiền.','2025-12-13 10:06:50'),(24,'Khuyến mãi','Khách hàng thân thiết có ưu đãi gì?','Thành viên hạng Vàng và Kim Cương sẽ được giảm thêm 5-10% giá phòng và ưu tiên check-in sớm.','2025-12-13 10:06:50');
/*!40000 ALTER TABLE `help` ENABLE KEYS */;
UNLOCK TABLES;

