/*!40000 ALTER TABLE `hotels` DISABLE KEYS */;
INSERT INTO `hotels` VALUES (1,'Grand Hotel','123 Nguyen Trai, Ha Noi','Ha Noi','0987654321',4.0,'/Hotel/Grand_Hotel/grand_hotel.jpg','Tọa lạc tại vị trí đắc địa nhất trung tâm thành phố, Grand Hotel hiện lên như một tòa lâu đài tráng lệ với lối kiến trúc cổ điển pha lẫn hiện đại đầy tinh tế. Bước chân vào đại sảnh, du khách sẽ choáng ngợp trước vẻ đẹp lộng lẫy của những chùm đèn pha lê rực rỡ và phong cách phục vụ chuẩn mực, tận tâm. Không chỉ là nơi nghỉ ngơi, khách sạn còn là biểu tượng của sự thành đạt, nơi những doanh nhân và du khách thượng lưu lựa chọn để tận hưởng những dịch vụ đẳng cấp nhất cùng trải nghiệm ẩm thực tinh hoa khó quên.','Available',8.90,'1 - 2','2025-04-16 15:06:45','2025-12-14 12:05:27'),(2,'Ocean View','456 Tran Phu, Da Nang','Da Nang','0971234567',4.0,'/Hotel/Ocean_View/ocean_view.jpg','Khách sạn hướng biển tuyệt đẹp. Mang đến cho du khách trải nghiệm ngắm cảnh biển vào bình minh, hoàng hôn tuyệt vời. Với dịch vụ 4 sao cung cấp đầy đủ mọi tiện nghi mà khách hàng cần.','Available',9.10,'4 - 5','2025-04-16 15:06:45','2026-01-19 20:17:54'),(3,'Mountain Retreat','789 Hoang Lien, Lao Cai','Lao Cai','0963456789',4.0,'/Hotel/Mountain_Retreat/mountain_retreat.jpg','Nằm ẩn mình giữa những cánh rừng thông bạt ngàn và sương mù lảng bảng, Mountain Retreat mang đến một không gian tĩnh lặng, tách biệt hoàn toàn với phố thị ồn ào. Khu nghỉ dưỡng được thiết kế hài hòa với thiên nhiên, sử dụng vật liệu gỗ và đá tự nhiên tạo cảm giác ấm cúng, mộc mạc nhưng vẫn đầy đủ tiện nghi hiện đại. Tại đây, bạn có thể cuộn mình bên lò sưởi ấm áp, thưởng thức một tách trà nóng và lắng nghe tiếng chim hót, tận hưởng những giây phút bình yên hiếm hoi để chữa lành tâm hồn.','Available',8.50,'4 - 5','2025-04-16 15:06:45','2025-12-14 12:05:27'),(4,'Sunshine Hotel','321 Le Loi, Ho Chi Minh City','Ho Chi Minh City','0956781234',4.0,'/Hotel/Sunshine_Hotel/sunshine_hotel.jpg','Mang trong mình nguồn năng lượng tươi mới và rực rỡ như ánh mặt trời, Sunshine Hotel là điểm dừng chân lý tưởng cho những gia đình trẻ và nhóm bạn yêu thích sự năng động. Khách sạn gây ấn tượng với thiết kế nội thất đầy màu sắc, không gian sinh hoạt chung rộng rãi và các dịch vụ giải trí đa dạng phù hợp mọi lứa tuổi. Từ bữa sáng đầy dinh dưỡng đến đội ngũ nhân viên thân thiện luôn nở nụ cười, Sunshine Hotel cam kết mang lại cho du khách một kỳ nghỉ tràn ngập niềm vui và sự hứng khởi trong từng khoảnh khắc.','Available',7.80,'1 - 2','2025-04-16 15:06:45','2025-12-13 15:32:42'),(5,'Paradise Resort','555 Bai Dai, Phu Quoc','Phu Quoc','0945678912',4.0,'/Hotel/Paradise_Resort/paradise_resort.jpg','Được ví như một ốc đảo xanh mát giữa lòng nhiệt đới, Paradise Resort mở ra một thế giới nghỉ dưỡng xa hoa với hệ thống biệt thự riêng tư nằm xen kẽ giữa những khu vườn nhiệt đới rực rỡ. Nơi đây sở hữu bãi biển riêng tuyệt đẹp cùng chuỗi dịch vụ spa trị liệu cao cấp, giúp du khách đắm chìm trong sự thư giãn tột cùng của cơ thể và tâm trí. Dù là tuần trăng mật lãng mạn hay kỳ nghỉ gia đình, Paradise Resort đều hứa hẹn mang đến những trải nghiệm thiên đường với sự chăm sóc tỉ mỉ đến từng chi tiết nhỏ nhất.','Available',9.50,'2 - 3','2025-04-16 15:06:45','2025-12-14 12:05:27'),(6,'Lakeview Inn','222 West Lake, Ha Noi','Ha Noi','0934567891',3.0,'/Hotel/Lakeview_Inn/lakeview_inn.jpg','Nằm soi bóng bên mặt hồ phẳng lặng và thơ mộng, Lakeview Inn mang vẻ đẹp dịu dàng và lãng mạn, là chốn dừng chân hoàn hảo cho những ai đang tìm kiếm sự tĩnh tại. Không gian nơi đây phảng phất nét cổ điển, với những ô cửa sổ lớn đón trọn khung cảnh hoàng hôn tím biếc buông xuống mặt hồ mỗi buổi chiều tà. Du khách có thể tản bộ trên những con đường nhỏ quanh hồ, thưởng thức cà phê trong vườn và cảm nhận nhịp sống trôi chậm lại, bỏ quên mọi hối hả, xô bồ ở phía sau lưng.','Available',7.20,'2 - 3','2025-04-16 15:06:45','2025-12-14 12:05:27'),(7,'Skyline Hotel','777 Dien Bien Phu, Da Nang','Da Nang','0923456789',4.0,'/Hotel/Skyline_Hotel/skyline_hotel.jpg','Tự hào vươn mình trên những tầng cao chọc trời, Skyline Hotel mang đến tầm nhìn panorama 360 độ ngoạn mục bao quát toàn cảnh thành phố lung linh ánh đèn. Khách sạn là sự lựa chọn hàng đầu của giới doanh nhân và du khách sành điệu nhờ phong cách thiết kế tối giản, hiện đại cùng hệ thống Sky Bar đẳng cấp trên tầng thượng. Tại đây, bạn không chỉ được tận hưởng giấc ngủ êm ái trên những tầng mây mà còn được trải nghiệm nhịp sống sôi động, hào nhoáng của đô thị từ một góc nhìn hoàn toàn khác biệt và đầy kiêu hãnh.','Available',8.70,'2 - 3','2025-04-16 15:06:45','2025-12-14 12:05:27'),(8,'Royal Palace','999 Nguyen Hue, Ho Chi Minh City','Ho Chi Minh City','0912345678',4.0,'/Hotel/Royal_Palace/royal_palace.jpg','Lấy cảm hứng từ những cung điện hoàng gia châu Âu, Royal Palace chinh phục du khách ngay từ cái nhìn đầu tiên bằng kiến trúc bề thế, nội thất dát vàng và những bức phù điêu chạm khắc tinh xảo. Mỗi căn phòng là một không gian nghệ thuật vương giả, nơi bạn được phục vụ như những bậc đế vương với các tiện ích xa xỉ và riêng tư tuyệt đối. Royal Palace không chỉ là nơi lưu trú, mà còn là nơi khẳng định đẳng cấp, mang đến cho du khách cơ hội trải nghiệm cuộc sống quý tộc giữa thời hiện đại.','Available',9.00,'4 - 5','2025-04-16 15:06:45','2025-12-14 12:05:27'),(9,'Cozy Homestay','123 Ly Thuong Kiet, Hue','Hue','0909876543',3.0,'/Hotel/Cozy_Homestay/cozy_homestay.jpg','Nhỏ nhắn, xinh xắn và tràn ngập hơi ấm gia đình, Cozy Homestay là nơi bạn tìm thấy sự kết nối chân thành và những trải nghiệm văn hóa bản địa gần gũi nhất. Không gian được bài trí mộc mạc với những vật dụng handmade dễ thương, cùng mùi hương của những món ăn nhà làm thơm phức từ căn bếp nhỏ luôn đỏ lửa. Tại Cozy Homestay, du khách không còn là người lạ, mà trở thành những người bạn thân thiết, cùng nhau chia sẻ những câu chuyện đời thường bên tách trà ấm trong một không gian yên bình như chính ngôi nhà của mình.','Available',6.80,'4 - 5','2025-04-16 15:06:45','2025-12-14 12:05:27'),(10,'Eco Lodge','888 National Forest, Da Lat','Da Lat','0898765432',4.0,'/Hotel/Eco_Lodge/eco_lodge.jpg','Eco Lodge là tiên phong trong xu hướng du lịch bền vững, nơi các công trình kiến trúc được xây dựng chủ yếu từ tre, nứa và vật liệu thân thiện môi trường, nằm hòa mình tuyệt đối vào thiên nhiên hoang sơ. Khu nghỉ dưỡng nói không với các thiết bị điện tử ồn ào, thay vào đó là những hoạt động thiền, yoga và trải nghiệm nông nghiệp thực tế. Đây là nơi lý tưởng để bạn thanh lọc cơ thể, hít thở bầu không khí trong lành tinh khiết và học cách trân trọng, bảo vệ vẻ đẹp của mẹ thiên nhiên.','Available',8.30,'1 - 2','2025-04-16 15:06:45','2025-12-13 15:32:42'),(11,'Grand Plaza Hanoi','117 Tran Duy Hung','Ha Noi','02435551000',5.0,'/Hotel/Grand_Plaza/grand_plaza.jpg','Nổi bật tại khu vực phía Tây thủ đô, Grand Plaza Hanoi gây ấn tượng mạnh mẽ với kiến trúc dát vàng lộng lẫy và trần sảnh cao vút đầy uy quyền. Là một trong những khách sạn 5 sao có trung tâm hội nghị lớn nhất Hà Nội, nơi đây thường xuyên được chọn làm địa điểm tổ chức các sự kiện quốc tế quan trọng. Với hệ thống phòng nghỉ sang trọng mang đậm phong cách hoàng gia cùng các tiện ích giải trí đa dạng như hồ bơi trong nhà và casino, Grand Plaza mang đến trải nghiệm nghỉ dưỡng và công tác đẳng cấp, tiện nghi bậc nhất.','Available',8.50,'1 - 2','2025-11-28 15:59:51','2025-12-14 12:05:27'),(12,'Rex Hotel Saigon','141 Nguyen Hue','Ho Chi Minh','02838292185',5.0,'/Hotel/Rex_Hotel/rex_hotel.jpg','Là chứng nhân lịch sử bền bỉ giữa lòng Sài Gòn, Rex Hotel Saigon tọa lạc ngay phố đi bộ Nguyễn Huệ, mang trong mình vẻ đẹp hoài cổ và thanh lịch của kiến trúc Đông Dương. Điểm nhấn đặc biệt của Rex chính là khu vườn thượng uyển Rooftop Garden nổi tiếng, nơi du khách có thể nhâm nhi ly cocktail và ngắm nhìn nhịp sống hối hả của thành phố từ trên cao. Khách sạn là sự kết hợp hoàn hảo giữa giá trị di sản và tiện nghi hiện đại, là điểm đến không thể bỏ qua cho những ai muốn cảm nhận Hòn ngọc Viễn Đông xưa và nay.','Available',9.10,'1 - 2','2025-11-28 15:59:51','2025-12-14 12:05:27'),(13,'Novotel Danang','36 Bach Dang','Da Nang','02363929999',4.0,'/Hotel/Novotel_Danang/novotel.jpg','Sở hữu vị trí tọa sơn hướng thủy ngay bên bờ sông Hàn thơ mộng, Novotel Danang là tòa tháp hiện đại biểu tượng cho sự năng động của thành phố biển miền Trung. Khách sạn cung cấp các căn hộ và phòng nghỉ với thiết kế mở, thu trọn tầm nhìn ra cầu Rồng và biển Mỹ Khê xinh đẹp. Đặc biệt, với quầy bar Sky36 cao nhất Đà Nẵng, Novotel là điểm đến lý tưởng cho những du khách yêu thích không khí lễ hội, âm nhạc sôi động và những màn trình diễn pháo hoa rực rỡ ngay từ ban công phòng mình.','Available',8.80,'4 - 5','2025-11-28 15:59:51','2025-12-14 12:05:27'),(14,'InterContinental PQ','Bai Truong','Phu Quoc','02973978888',5.0,'/Hotel/InterContinental_PQ/intercon.jpg','Tọa lạc lại Bãi Trường với vẻ đẹp hoang sơ, InterContinental Phu Quoc Long Beach Resort là kiệt tác nghỉ dưỡng kết hợp giữa sự sang trọng quốc tế và thiên nhiên đảo ngọc. Khu nghỉ dưỡng nổi tiếng với quán bar INK 360 thiết kế hình bạch tuộc độc đáo trên tầng thượng, nơi ngắm hoàng hôn đẹp nhất Phú Quốc. Với các biệt thự hướng biển, hệ thống hồ bơi vô cực và các hoạt động giải trí dành riêng cho gia đình, đây là lựa chọn hoàn hảo cho một kỳ nghỉ dưỡng biệt lập, đẳng cấp và đầy ắp kỷ niệm đáng nhớ.','Available',9.50,'2 - 3','2025-11-28 15:59:51','2025-12-14 12:05:27'),(15,'Dalat Palace','12 Tran Phu','Da Lat','02633825444',5.0,'/Hotel/Dalat_Palace/dalat_palace.jpg','Như một tòa lâu đài Pháp cổ kính ngự trị trên đồi thông nhìn xuống Hồ Xuân Hương, Dalat Palace Heritage Hotel gìn giữ nguyên vẹn vẻ đẹp quý phái từ thời thuộc địa. Bước vào khách sạn, du khách như lạc vào một bảo tàng nghệ thuật với sàn gỗ sồi, lò sưởi cổ và những chùm đèn pha lê lấp lánh nhuốm màu thời gian. Cùng với sân golf lâu đời và dịch vụ trà chiều tao nhã, Dalat Palace mang đến một trải nghiệm nghỉ dưỡng vương giả, lãng mạn và đậm chất thơ giữa lòng thành phố ngàn hoa.','Available',9.20,'4 - 5','2025-11-28 15:59:51','2025-12-14 12:05:27'),(16,'Sheraton Nha Trang','26 Tran Phu','Nha Trang','02583880000',5.0,'/Hotel/Sheraton_NT/sheraton.jpg','Nằm kiêu hãnh trên con đường vàng Trần Phú, Sheraton Nha Trang là một trong những khách sạn quốc tế hiếm hoi sở hữu 100% phòng nghỉ đều có tầm nhìn hướng biển tuyệt đẹp. Du khách có thể đón bình minh ngay tại giường ngủ, thư giãn tại hồ bơi vô cực trên cao hoặc tham gia lớp học nấu ăn thú vị tại trường dạy nấu ăn đầu tiên trong khách sạn 5 sao ở Việt Nam. Dịch vụ chuyên nghiệp cùng vị trí thuận tiện giúp Sheraton luôn là cái tên hàng đầu cho kỳ nghỉ biển sôi động tại Nha Trang.','Available',9.00,'2 - 3','2025-11-28 15:59:51','2025-12-14 12:05:27'),(17,'Silk Path Sapa','Doi Quan 6','Sapa','02143788555',5.0,'/Hotel/Silk_Path/silk_path.jpg','Tựa như một lâu đài châu Âu tráng lệ ẩn hiện giữa mây ngàn Tây Bắc, Silk Path Grand Sapa ôm trọn vẻ đẹp hùng vĩ của dãy Hoàng Liên Sơn vào trong tầm mắt. Khu nghỉ dưỡng sở hữu vườn hồng cổ thụ rực rỡ quanh năm cùng kiến trúc Đông Dương tinh tế, sang trọng đến từng chi tiết. Tại đây, du khách sẽ được tận hưởng cảm giác bồng bềnh như đi trên mây, trải nghiệm tắm lá thuốc người Dao đỏ và thưởng thức ẩm thực vùng cao trong một không gian nghỉ dưỡng thượng lưu, ấm áp giữa cái lạnh đặc trưng của phố núi.','Available',9.30,'3 - 4','2025-11-28 15:59:51','2025-12-14 12:05:27'),(18,'Vinpearl Ha Long','Reu Island','Ha Long','02033556868',5.0,'/Hotel/Vinpearl_HL/vinpearl.jpg','Nằm biệt lập hoàn toàn trên đảo Rều, Vinpearl Resort & Spa Hạ Long hiện lên sừng sững như một cung điện nguy nga giữa mặt biển xanh thẳm. Với thiết kế hình cánh cung ôm lấy biển và bốn mặt đều giáp nước, khu nghỉ dưỡng mang đến tầm nhìn 360 độ ra Vịnh Hạ Long kỳ vĩ. Du khách sẽ di chuyển bằng tàu cao tốc riêng để đến đảo, tận hưởng sự riêng tư tuyệt đối, hồ bơi ngoài trời rộng lớn và dịch vụ đẳng cấp 5 sao, biến kỳ nghỉ thành một chuyến du ngoạn hoàng gia thực thụ.','Available',8.90,'1 - 2','2025-11-28 15:59:51','2025-12-14 12:05:27'),(19,'Imperial Hue','8 Hung Vuong','Hue','02343882222',5.0,'/Hotel/Imperial_Hue/imperial.jpg','Là khách sạn 5 sao đầu tiên tại Cố đô Huế, Imperial Hotel mang đậm dấu ấn kiến trúc cung đình với những đường nét hoa văn chạm trổ rồng phượng tinh xảo. Tọa lạc ngay sát bờ sông Hương êm đềm, khách sạn là sự giao thoa tuyệt vời giữa nét đẹp văn hóa truyền thống và tiện nghi hiện đại. Từ đây, du khách dễ dàng tản bộ đến cầu Trường Tiền, thưởng thức Nhã nhạc cung đình và đắm mình trong không gian hoài cổ, trầm mặc nhưng vô cùng sang trọng của vùng đất kinh kỳ.','Available',8.70,'1 - 2','2025-11-28 15:59:51','2025-12-13 15:32:42'),(20,'Flamingo Dai Lai','Ngoc Thanh','Vinh Phuc','02116266666',5.0,'/Hotel/Flamingo_DL/flamingo.jpg','Chỉ cách Hà Nội khoảng một giờ di chuyển, Flamingo Đại Lải Resort là vùng đất của nghệ thuật và thiên nhiên, nơi sở hữu hàng loạt giải thưởng kiến trúc xanh quốc tế. Những căn biệt thự tại đây nằm ẩn mình dưới tán thông xanh mát hoặc ven hồ Đại Lải mênh mông, tạo nên không gian nghỉ dưỡng sinh thái trong lành và biệt lập. Với tổ hợp tiện ích khổng lồ từ sân golf, spa, bảo tàng nghệ thuật đến công viên vui chơi, Flamingo là điểm đến lý tưởng để đi trốn khói bụi thành phố và tái tạo năng lượng.','Available',8.60,'1 - 2','2025-11-28 15:59:51','2025-12-14 12:05:27'),(21,'Pullman Vung Tau','15 Thi Sach','Vung Tau','02543551777',5.0,'/Hotel/Pullman_VT/pullman.jpg','Mang đến làn gió hiện đại và phong cách quốc tế cho thành phố biển, Pullman Vung Tau nổi bật với kiến trúc mái vòm vàng độc đáo và không gian tiền sảnh ngập tràn ánh sáng. Khách sạn là sự kết hợp cân bằng giữa công việc và nghỉ dưỡng (Bleisure), sở hữu trung tâm hội nghị lớn và vị trí thuận tiện gần các khu vui chơi, mua sắm. Du khách có thể thư giãn tại hồ bơi ngoài trời tuyệt đẹp, thưởng thức hải sản tươi ngon và tận hưởng dịch vụ chuẩn 5 sao năng động, trẻ trung ngay tại cửa ngõ Vũng Tàu.','Available',8.40,'4 - 5','2025-11-28 15:59:51','2025-12-14 12:05:27'),(22,'Muong Thanh Da Nang','270 Vo Nguyen Giap','Da Nang','02363956789',4.0,'/Hotel/Muong_Thanh_DN/muong_thanh.jpg','Tọa lạc ngay đối diện bãi biển Mỹ Khê – một trong những bãi biển đẹp nhất hành tinh, Mường Thanh Luxury Đà Nẵng là điểm dừng chân quen thuộc với du khách trong và ngoài nước. Khách sạn mang đến không gian nghỉ dưỡng ấm cúng, tiện nghi với mức chi phí hợp lý, cùng hệ thống phòng hội nghị quy mô lớn. Từ cửa sổ phòng nghỉ, bạn có thể phóng tầm mắt ngắm nhìn biển xanh cát trắng trải dài tít tắp, tận hưởng sự phục vụ tận tình và lòng hiếu khách đặc trưng của thương hiệu khách sạn thuần Việt này.','Available',7.90,'1 - 2','2025-11-28 15:59:51','2025-12-14 12:05:27'),(23,'Metropole Hanoi','15 Ngo Quyen','Ha Noi','02438266919',5.0,'/Hotel/Metropole/metropole.jpg','Hơn cả một khách sạn, Sofitel Legend Metropole Hanoi là một di sản sống động với hơn một thế kỷ lịch sử, mang vẻ đẹp kiến trúc Pháp cổ điển đầy lãng mạn và quý phái. Nằm giữa lòng khu phố Pháp, khách sạn từng là nơi đón tiếp các nguyên thủ quốc gia, văn nghệ sĩ lừng danh thế giới. Với hầm trú ẩn lịch sử, chiếc xe Citroën cổ kính và không gian sân vườn xanh mát, Metropole không chỉ là nơi lưu trú mà là hành trình du hành thời gian về một Hà Nội thanh lịch, hào hoa của quá khứ.','Available',9.80,'2 - 3','2025-11-28 15:59:51','2025-12-14 12:05:27'),(24,'Liberty Central','17 Ton Duc Thang','Ho Chi Minh','02838271717',4.0,'/Hotel/Liberty_Central/liberty.jpg','Thuộc chuỗi khách sạn thành phố năng động, Liberty Central mang phong cách thiết kế hiện đại, tối giản và đề cao tính tiện dụng. Khách sạn luôn tọa lạc tại những vị trí trung tâm sầm uất, giúp du khách dễ dàng hòa mình vào nhịp sống đô thị nhộn nhịp hay khám phá các địa điểm du lịch nổi tiếng. Với hồ bơi trên tầng thượng, bữa sáng đa dạng và dịch vụ nhanh chóng, Liberty Central là lựa chọn tối ưu cho những du khách hiện đại ưu tiên sự thuận tiện và thoải mái.','Available',8.50,'1 - 2','2025-11-28 15:59:51','2025-12-14 12:05:27'),(25,'Victoria Hoi An','Cua Dai Beach','Hoi An','02353927040',4.0,'/Hotel/Victoria_HoiAn/victoria.jpg','Mô phỏng một làng chài truyền thống với những con ngõ nhỏ lát gạch và mái ngói rêu phong, Victoria Hoi An Beach Resort & Spa mang vẻ đẹp mộc mạc nhưng đầy quyến rũ. Nằm kề bên biển Cửa Đại và sông Thu Bồn, khu nghỉ dưỡng mang đến cảm giác bình yên với một bên là biển xanh, một bên là đồng lúa bát ngát. Du khách sẽ đặc biệt ấn tượng với trải nghiệm tham quan phố cổ bằng xe Sidecar độc đáo, hay đơn giản là thư giãn trong không gian đậm chất văn hóa Hội An xưa cũ.','Available',9.00,'4 - 5','2025-11-28 15:59:51','2025-12-14 12:05:27'),(26,'Sapa Horizon','018 Pham Xuan Huan','Sapa','0987654322',3.0,'/Hotel/Sapa_Horizon/horizon.jpg','Nằm ngay trung tâm thị trấn nhưng vẫn giữ được sự yên tĩnh cần thiết, Sapa Horizon Hotel là một trong những khách sạn boutique được yêu thích nhất Sapa nhờ tầm nhìn triệu đô. Hầu hết các phòng nghỉ đều có ban công hướng thẳng ra thung lũng Mường Hoa và dãy Fansipan hùng vĩ, nơi bạn có thể săn mây ngay tại giường ngủ. Sự hiếu khách nồng hậu của đội ngũ nhân viên cùng những bữa sáng ấm cúng phục vụ tại phòng khiến du khách luôn cảm thấy thân thuộc và được trân trọng như đang ở nhà.','Available',9.60,'3 - 4','2025-11-28 15:59:51','2025-12-14 12:05:27'),(27,'Six Senses Con Dao','Dat Doc Beach','Con Dao','02543831222',5.0,'/Hotel/Six_Senses/six_senses.jpg','Là đỉnh cao của sự xa hoa và riêng tư, Six Senses Côn Đảo là khu nghỉ dưỡng 5 sao quốc tế đầu tiên tại quần đảo linh thiêng này, nằm trải dài dọc theo bãi biển Đất Dốc hoang sơ. Các biệt thự gỗ được xây dựng hài hòa với thiên nhiên, đều sở hữu hồ bơi vô cực riêng hướng biển, mang lại sự tĩnh lặng tuyệt đối. Đây là nơi trú ẩn hoàn hảo cho giới thượng lưu và những ngôi sao nổi tiếng muốn tìm kiếm sự an yên, tách biệt hoàn toàn với thế giới bên ngoài và tận hưởng các liệu trình wellness đẳng cấp.','Available',9.70,'3 - 4','2025-11-28 15:59:51','2025-12-14 12:05:27'),(28,'Legacy Yen Tu','Thuong Yen Cong','Uong Bi','02033598888',5.0,'/Hotel/Legacy_YenTu/legacy.jpg','Được kiến tạo bởi phù thủy kiến trúc Bill Bensley, Legacy Yên Tử tái hiện không gian cung điện thời Trần thế kỷ 13 đầy uy nghiêm và huyền bí dưới chân núi Yên Tử linh thiêng. Công trình sử dụng các vật liệu thủ công truyền thống như trấu, gốm, đồng tạo nên vẻ đẹp cổ kính, trầm mặc hiếm có. Tại đây, du khách không chỉ nghỉ dưỡng mà còn tham gia vào hành trình tìm về bản ngã qua các lớp thiền, yoga và thưởng thức ẩm thực chay tịnh, mang lại sự cân bằng và thanh thản cho tâm hồn.','Available',9.30,'3 - 4','2025-11-28 15:59:51','2025-12-14 12:05:27'),(29,'Seashells Phu Quoc','1 Vo Thi Sau','Phu Quoc','02973923999',5.0,'/Hotel/Seashells/seashells.jpg','Nổi bật với thiết kế hình con tàu khổng lồ vươn mình ra khơi, Seashells Phu Quoc tọa lạc ngay trung tâm thị trấn Dương Đông, sát cạnh Dinh Cậu và Chợ Đêm sầm uất. Vị trí đắc địa này cho phép du khách vừa tận hưởng bãi biển riêng tư, vừa dễ dàng hòa mình vào cuộc sống về đêm sôi động của đảo ngọc chỉ với vài bước chân. Tất cả các phòng đều có ban công hướng biển, là nơi lý tưởng để chiêm ngưỡng hoàng hôn rực rỡ và tận hưởng tiện nghi hiện đại, trẻ trung.','Available',8.90,'4 - 5','2025-11-28 15:59:51','2025-12-14 12:05:27'),(30,'Melia Vinpearl TH','Le Thanh Ton','Thanh Hoa','02373918888',5.0,'/Hotel/Melia_ThanhHoa/melia.jpg','Là tòa tháp cao nhất xứ Thanh, Melia Vinpearl Thanh Hóa kiêu hãnh vươn mình giữa trung tâm thành phố như một biểu tượng của sự phồn vinh và hiện đại. Khách sạn cung cấp tầm nhìn toàn cảnh bao quát thành phố nhộn nhịp, tích hợp cùng trung tâm thương mại Vincom sầm uất ngay dưới chân đế. Với hệ thống phòng nghỉ tiêu chuẩn quốc tế, bể bơi bốn mùa và dịch vụ hội nghị chuyên nghiệp, đây là điểm dừng chân sang trọng bậc nhất, đáp ứng mọi nhu cầu của du khách khi đến thăm vùng đất địa linh nhân kiệt này.','Available',8.60,'2 - 3','2025-11-28 15:59:51','2025-12-14 12:05:27'),(32,'Time','123 Hoang Mai','Ha Noi','188',5.0,'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRKFoo8y4kLV98oUwTZTAQCzqmlJUqOR0NLFg&s','view','Fully booked',8.00,'10','2025-12-20 16:07:14','2025-12-20 17:41:05');
